parameters.jsCode:
const account = $input.item.json;

const daysToRenewal = Math.floor((new Date(account.renewal_date) - new Date()) / (1000*60*60*24));
let riskLevel = 'Low';
const riskSignals = [];

// Usage decline
if (account.usage_trend < -15) {
  riskSignals.push(`Usage declined ${Math.abs(account.usage_trend)}% over 30 days`);
}

// Support issues
if (account.open_tickets > 3) {
  riskSignals.push(`${account.open_tickets} open support tickets`);
}

// Low NPS
if (account.latest_nps !== null && account.latest_nps < 7) {
  riskSignals.push(`NPS score: ${account.latest_nps}`);
}

// No recent engagement
if (account.days_since_last_meeting > 30) {
  riskSignals.push(`No meeting in ${account.days_since_last_meeting} days`);
}

// Champion departure
if (account.champion_status === 'departed') {
  riskSignals.push('Champion has left the organization');
}

if (riskSignals.length >= 3) riskLevel = 'High';
else if (riskSignals.length >= 1) riskLevel = 'Medium';

const actions = [];
if (riskLevel === 'High') actions.push('Schedule executive sponsor call within 1 week');
if (account.champion_status === 'departed') actions.push('Identify new champion contact');
if (account.usage_trend < -15) actions.push('Arrange product re-engagement session');
if (account.open_tickets > 3) actions.push('Escalate open support tickets');
if (riskLevel !== 'Low') actions.push('Prepare renewal risk mitigation plan');

return [{
  json: {
    account_id: account.account_id,
    account_name: account.account_name,
    arr: account.arr,
    renewal_date: account.renewal_date,
    days_to_renewal: daysToRenewal,
    risk_level: riskLevel,
    risk_signals: riskSignals,
    recommended_actions: actions,
    csm_email: account.csm_email,
    csm_name: account.csm_name
  }
}];

